mapper.select:
SELECT m.id, b.brand_name as mentorName, m.mentor_user_id as mentorUserId, b.avator as mentorAvatar, m.past_year_messages as pastYearMessages, m.guidance_period_earning as guidancePeriodEarning, m.guidance_period_influencers as guidancePeriodInfluencers, m.guidance_period_messages as guidancePeriodMessages, m.status, m.create_at as createAt FROM mentorship m INNER JOIN brand b ON m.mentor_brand_id = b.id WHERE m.mentee_brand_id = #{menteeBrandId}
AND locate(#{dto.q}, b.brand_name)>0
AND m.status = #{dto.status}
ORDER BY m.create_at DESC
